package com.desafio.hotel.services.checkin;

import com.desafio.hotel.dto.checkin.CheckinCreateDto;
import com.desafio.hotel.entity.checkin.Checkin;
import java.util.List;

/**
 * Interface para o serviço de Checkin. Define as operações públicas esperadas
 * pela aplicação. Implementada por CheckinServiceImpl.
 */
public interface CheckinService {
    Checkin criarCheckin(CheckinCreateDto dto);
    String deletarCheckin(Long id);
    List<Checkin> findByGuestId(Long id);
    Checkin findById(Long id);
}

package com.desafio.hotel.services.checkin;

import com.desafio.hotel.dto.checkin.CheckinCreateDto;
import com.desafio.hotel.entity.checkin.Checkin;
import com.desafio.hotel.entity.guest.Guest;
import com.desafio.hotel.exceptions.BadRequestException;
import com.desafio.hotel.exceptions.GuestNotFoundException;
import com.desafio.hotel.repositories.CheckinRepository;
import com.desafio.hotel.services.guests.GuestService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import java.util.List;

/**
 * Serviço responsável pela gestão de check-ins de hóspedes.
 *
 * <p>Esta classe fornece operações para criar, deletar e recuperar check-ins
 * de hóspedes no hotel.</p>
 *
 * <p>Funcionalidades principais:</p>
 * <ul>
 *   <li>Criar um novo check-in para um hóspede</li>
 *   <li>Deletar um check-in existente</li>
 *   <li>Buscar check-ins por ID do hóspede ou por ID do check-in</li>
 * </ul>
 *
 * @author Kaike Tinoco
 * @version 1.0
 * @since 1.0
 */
@Service
public class CheckinServiceImpl implements CheckinService {

    private final CheckinRepository repository;

    private final GuestService guestService;

    @Autowired
    public CheckinServiceImpl(CheckinRepository repository, GuestService guestService) {
        this.repository = repository;
        this.guestService = guestService;
    }

    /**
     * Cria um novo check-in para um hóspede.
     *
     * @param dto objeto contendo os dados do check-in (ID do hóspede, data de entrada e adicional de veículo)
     * @return o objeto Checkin criado
     * @throws BadRequestException se houver erro durante a criação do check-in
     */
    @Override
    public Checkin criarCheckin(CheckinCreateDto dto) {
        try {
            Checkin checkin = new Checkin();
            Guest novoHospede = guestService.findById(dto.getGuestId());
            checkin.setGuest(novoHospede);
            checkin.setDataEntrada(dto.getDataEntrada());
            checkin.setAdicionalVeiculo(dto.isAdicionalVeiculo());
            repository.save(checkin);
            return checkin;
        } catch (BadRequestException e){
            throw new BadRequestException(e.getMessage());
        }
    }

    /**
     * Deleta um check-in existente.
     *
     * @param id identificador único do check-in a ser deletado
     * @return mensagem confirmando a exclusão do check-in
     * @throws BadRequestException se o ID for nulo ou o check-in não existir
     */
    @Override
    public String deletarCheckin(Long id) {
        if (id == null){
            throw new BadRequestException("Por favor informe um id válido");
        }
        try {
            Checkin checkin = repository.findById(id).orElseThrow(() ->
                    new BadRequestException("Checkin não encontrado, id inváldo"));
            repository.delete(checkin);
            return "Checkin deletado com sucesso!";
        }catch (BadRequestException e){
            throw new BadRequestException(e.getMessage());
        }
    }

    /**
     * Busca todos os check-ins associados a um hóspede específico.
     *
     * @param id identificador único do hóspede
     * @return lista de check-ins do hóspede
     * @throws BadRequestException se o ID for nulo ou nenhum check-in for encontrado
     */
    @Override
    public List<Checkin> findByGuestId(Long id)  {
        if (id == null){
            throw new BadRequestException("Por favor informe um id válido");
        }
        return repository.findByGuestId(id).orElseThrow(()
                -> new BadRequestException("não foi possivel encontrar checkins associados a este hospede "));
    }

    /**
     * Busca um check-in específico por ID.
     *
     * @param id identificador único do check-in
     * @return o check-in encontrado
     * @throws BadRequestException se o ID for nulo
     * @throws GuestNotFoundException se o check-in não for encontrado
     */
    @Override
    public Checkin findById(Long id)  {
        if (id == null){
            throw new BadRequestException("Por favor informe um id válido");
        }
        return repository.findById(id).orElseThrow(()-> new GuestNotFoundException("não há hospede com esse id"));
    }


}

package com.desafio.hotel.services.checkout;

import com.desafio.hotel.dto.response.ResponseDTO;
import com.desafio.hotel.entity.checkout.Checkout;
import java.util.List;

/**
 * Interface para o serviço de Checkout. Implementada por CheckoutServiceImpl.
 */
public interface CheckoutService {
    Checkout criarCheckout(Long id);
    List<Checkout> findByCheckinId(Long id);
    List<ResponseDTO> buscarTodosHospedesNoHotel();
    List<ResponseDTO> buscarTodosHospedesForaHotel();
}

package com.desafio.hotel.services.checkout;

import com.desafio.hotel.dto.response.ResponseDTO;
import com.desafio.hotel.entity.checkin.Checkin;
import com.desafio.hotel.entity.checkout.Checkout;
import com.desafio.hotel.entity.guest.Guest;
import com.desafio.hotel.exceptions.BadRequestException;
import com.desafio.hotel.repositories.CheckoutRepository;
import com.desafio.hotel.services.checkin.CheckinService;
import com.desafio.hotel.services.estadia.CalculoEstadiaService;
import com.desafio.hotel.services.guests.GuestService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

/**
 * Serviço responsável pela gestão de check-outs de hóspedes.
 *
 * <p>Esta classe fornece operações para criar check-outs, recuperar informações
 * de hóspedes que estão dentro ou fora do hotel, e calcular os custos associados.</p>
 *
 * <p>Funcionalidades principais:</p>
 * <ul>
 *   <li>Criar um novo check-out baseado em um check-in</li>
 *   <li>Buscar check-outs por ID do check-in</li>
 *   <li>Listar todos os hóspedes atualmente no hotel</li>
 *   <li>Listar todos os hóspedes que saíram do hotel</li>
 *   <li>Calcular custos totais de hospedagens</li>
 * </ul>
 *
 * @author Kaike Tinoco
 * @version 1.0
 * @since 1.0
 */
@Service
public class CheckoutServiceImpl implements CheckoutService {

    private final CheckoutRepository repository;

    private final CheckinService checkinService;

    private final CalculoEstadiaService calculoEstadiaService;

    private final GuestService guestService;

    @Autowired
    public CheckoutServiceImpl(CheckoutRepository repository, CheckinService checkinService, CalculoEstadiaService calculoEstadiaService, GuestService guestService) {
        this.repository = repository;
        this.checkinService = checkinService;
        this.calculoEstadiaService = calculoEstadiaService;
        this.guestService = guestService;
    }

    /**
     * Cria um novo check-out baseado em um check-in existente.
     *
     * <p>Este método calcula automaticamente o valor total da estadia e marca
     * o hóspede como fora do hotel.</p>
     *
     * @param id identificador único do check-in
     * @return o objeto Checkout criado
     * @throws BadRequestException se o ID for nulo ou o check-in não existir
     */
    @Override
    public Checkout criarCheckout(Long id){
        if(id == null){
            throw new BadRequestException("id vazio, por favor envie um id válido");
        }
        try {
            Checkin checkin = checkinService.findById(id);
            Guest guest = checkin.getGuest();
            Checkout checkout = new Checkout();
            checkout.setCheckin(checkin);
            checkout.setDataSaida(LocalDateTime.now());
            BigDecimal valorTotal = calculoEstadiaService.calcularValorEstadia(checkin.getDataEntrada(),
                    LocalDateTime.now(), checkin.isAdicionalVeiculo());
            checkout.setValorTotal(valorTotal);
            guest.setDentroHotel(false);
            repository.save(checkout);
            return checkout;
        } catch (BadRequestException e){
            throw new BadRequestException(e.getMessage());
        }
    }

    /**
     * Busca todos os check-outs associados a um check-in específico.
     *
     * @param id identificador único do check-in
     * @return lista de check-outs do check-in
     * @throws BadRequestException se o ID for nulo ou nenhum check-out for encontrado
     */
    @Override
    public List<Checkout> findByCheckinId(Long id) {
        if (id == null){
            throw new BadRequestException("Id vazio, por favor informe um id válido");
        }
        try {
            return repository.findByCheckinId(id)
                    .orElseThrow(()-> new BadRequestException("não há nenhum checkout associado a esse cliente"));
        }catch (BadRequestException e){
            throw new BadRequestException(e.getMessage());

        }

    }

    /**
     * Busca todos os hóspedes que estão atualmente dentro do hotel.
     *
     * @return lista de RespostasDTO contendo dados dos hóspedes dentro do hotel
     * @throws BadRequestException se nenhum hóspede for encontrado
     */
    @Override
    public List<ResponseDTO> buscarTodosHospedesNoHotel() {
        return getResponseDTOS(true);
    }

    /**
     * Busca todos os hóspedes que saíram do hotel.
     *
     * @return lista de RespostasDTO contendo dados dos hóspedes fora do hotel
     * @throws BadRequestException se nenhum hóspede for encontrado
     */
    @Override
    public List<ResponseDTO> buscarTodosHospedesForaHotel() {
        return getResponseDTOS(false);
    }

    /**
     * Método auxiliar para construir a resposta de hóspedes.
     *
     * <p>Recupera os hóspedes de acordo com sua posição (dentro ou fora do hotel)
     * e calcula o total de despesas para cada um.</p>
     *
     * @param isDentroHotel indica se deve buscar hóspedes dentro (true) ou fora (false) do hotel
     * @return lista de RespostasDTO com informações dos hóspedes e custos
     * @throws BadRequestException se nenhum hóspede for encontrado
     */
    private List<ResponseDTO> getResponseDTOS(boolean isDentroHotel) {
        List<ResponseDTO> response = new ArrayList<>();
        List<Guest> guestList = guestService.buscarHospedeDentroOuForaHotel(isDentroHotel);
        if (guestList == null || guestList.isEmpty()){
            throw new BadRequestException("Hóspedes não econtrados");
        }
        try {
            for(Guest guest: guestList){
                BigDecimal valorGastoTotal;
                BigDecimal valorGastoAtual;
                List<Checkout> todosCheckouts = findByCheckinId(guest.getId());
                if(todosCheckouts.isEmpty()){
                    ResponseDTO responseDTO = ResponseDTO.builder()
                            .guest(guest)
                            .totalUltimaHospedagem(BigDecimal.ZERO)
                            .totalHospedagens(BigDecimal.ZERO)
                            .build();
                    response.add(responseDTO);
                }else{
                    valorGastoTotal = calculoEstadiaService.calcularTotalEstadias(guest.getId(),todosCheckouts);
                    valorGastoAtual = todosCheckouts.get(todosCheckouts.size() - 1).getValorTotal();
                    ResponseDTO responseDTO = ResponseDTO.builder()
                            .guest(guest)
                            .totalHospedagens(valorGastoTotal)
                            .totalUltimaHospedagem(valorGastoAtual)
                            .build();
                    response.add(responseDTO);
                }
            }
        } catch (BadRequestException e){
            throw new BadRequestException(e.getMessage());
        }
        return response;
    }


}

package com.desafio.hotel.services.estadia;

import com.desafio.hotel.entity.checkout.Checkout;
import java.math.BigDecimal;
import java.time.LocalDateTime;
import java.util.List;

/**
 * Interface para o serviço de cálculo de estadias. Implementada por CalculoEstadiaServiceImpl.
 */
public interface CalculoEstadiaService {
    BigDecimal calcularValorEstadia(LocalDateTime dataEntrada, LocalDateTime dataSaida, boolean adicionalVeiculo);
    BigDecimal calcularTotalEstadias(Long clienteId, List<Checkout> checkoutList);
}

package com.desafio.hotel.services.estadia;

import com.desafio.hotel.entity.checkout.Checkout;
import com.desafio.hotel.exceptions.BadRequestException;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.time.DayOfWeek;
import java.time.LocalDateTime;
import java.time.temporal.ChronoUnit;
import java.util.*;

/**
 * Serviço responsável pelo cálculo de estadias em hotel.
 *
 * <p>Esta classe fornece funcionalidades para calcular o valor total de uma estadia
 * baseado em datas de entrada e saída, considerando tarifa diferenciada para finais
 * de semana e a possibilidade de adicional por veículo.</p>
 *
 * <p>Funcionalidades principais:</p>
 * <ul>
 *   <li>Cálculo de valor de estadia com base em data de entrada e saída</li>
 *   <li>Consideração de tarifas diferenciadas para dias úteis e finais de semana</li>
 *   <li>Adicional de tarifa para hóspedes com veículo</li>
 *   <li>Cálculo do total de despesas por cliente ao longo de múltiplas estadias</li>
 * </ul>
 *
 * @author Kaike Tinoco
 * @version 1.0
 * @since 1.0
 */
@Service
public class CalculoEstadiaServiceImpl implements CalculoEstadiaService {

    /** Valor da diária em dia útil sem veículo */
    private static final BigDecimal VALOR_UTIL_SEM_CARRO = new BigDecimal("120");

    /** Valor da diária em dia útil com veículo */
    private static final BigDecimal VALOR_UTIL_COM_CARRO = new BigDecimal("140");

    /** Valor da diária em final de semana sem veículo */
    private static final BigDecimal VALOR_FINAL_SEMANA_SEM_CARRO = new BigDecimal("150");

    /** Valor da diária em final de semana com veículo */
    private static final BigDecimal VALOR_FINAL_SEMANA_COM_CARRO = new BigDecimal("170");

    /**
     * Calcula o valor total da estadia de um hóspede.
     *
     * <p>O cálculo considera:</p>
     * <ul>
     *   <li>Tarifa diferenciada para dias úteis e finais de semana</li>
     *   <li>Tarifa adicional se o hóspede tiver veículo</li>
     *   <li>Cobrança adicional se a saída ocorrer após as 16h30</li>
     * </ul>
     *
     * @param dataEntrada data e hora de entrada do hóspede
     * @param dataSaida data e hora de saída do hóspede
     * @param adicionalVeiculo indica se o hóspede possui veículo
     * @return o valor total da estadia em BigDecimal
     * @throws BadRequestException se a data de saída for anterior à data de entrada
     */
    @Override
    public BigDecimal calcularValorEstadia(LocalDateTime dataEntrada,
                                           LocalDateTime dataSaida,
                                           boolean adicionalVeiculo) {
        if (dataSaida.isBefore(dataEntrada)){
            throw new BadRequestException("A data de entrada não pode ser depois da data de saída!");
        }

        long totalDias = ChronoUnit.DAYS.between(dataEntrada.toLocalDate(), dataSaida.toLocalDate());
        long finaisDeSemana = contarFinaisDeSemana(dataEntrada, dataSaida);
        long diasUteis = totalDias - finaisDeSemana;

        BigDecimal valorDiaUtil = adicionalVeiculo ? VALOR_UTIL_COM_CARRO : VALOR_UTIL_SEM_CARRO;
        BigDecimal valorFinalDeSemana = adicionalVeiculo ? VALOR_FINAL_SEMANA_COM_CARRO : VALOR_FINAL_SEMANA_SEM_CARRO;

        BigDecimal valorTotal = valorDiaUtil.multiply(BigDecimal.valueOf(diasUteis))
                .add(valorFinalDeSemana.multiply(BigDecimal.valueOf(finaisDeSemana)));


        if (checarHoraSaida(dataSaida)) {
            if (dataSaida.getDayOfWeek() == DayOfWeek.SATURDAY || dataSaida.getDayOfWeek() == DayOfWeek.SUNDAY) {
                valorTotal = valorTotal.add(valorFinalDeSemana);
            } else {
                valorTotal = valorTotal.add(valorDiaUtil);
            }
        }

        return valorTotal;
    }

    /**
     * Conta o número de finais de semana entre duas datas.
     *
     * @param dataEntrada data de início da contagem
     * @param dataSaida data de fim da contagem
     * @return número total de dias que caem em finais de semana
     */
    private long contarFinaisDeSemana(LocalDateTime dataEntrada, LocalDateTime dataSaida) {
        long finaisDeSemana = 0;
        for (LocalDateTime data = dataEntrada; !data.toLocalDate().isAfter(dataSaida.toLocalDate());
             data = data.plusDays(1)) {
            if (data.getDayOfWeek() == DayOfWeek.SATURDAY || data.getDayOfWeek() == DayOfWeek.SUNDAY) {
                finaisDeSemana++;
            }
        }
        return finaisDeSemana;
    }

    /**
     * Verifica se o horário de saída ultrapassa as 16h30.
     *
     * <p>Se a saída ocorrer após este horário, uma diária adicional é cobrada.</p>
     *
     * @param dataSaida data e hora de saída a ser verificada
     * @return true se a hora é posterior às 16h30, false caso contrário
     */
    private boolean checarHoraSaida(LocalDateTime dataSaida) {
        if(dataSaida.getHour() > 16){
            return true;
        } else return dataSaida.getHour() == 16 && dataSaida.getMinute() == 30;
    }

    /** Mapa que armazena o total de despesas por cliente */
    private final Map<Long, BigDecimal> totalPorCliente = new HashMap<>();

    /** Mapa que rastreia quais checkouts já foram processados para cada cliente */
    private final Map<Long, Set<Long>> checkoutsProcessadosPorCliente = new HashMap<>();

    /**
     * Calcula o total de despesas de um cliente ao longo de múltiplas estadias.
     *
     * <p>Este método evita contar a mesma estadia duas vezes, rastreando os IDs
     * dos checkouts já processados para cada cliente.</p>
     *
     * @param clienteId identificador único do cliente
     * @param checkoutList lista de checkouts do cliente
     * @return o valor total acumulado das estadias do cliente
     */
    @Override
    public BigDecimal calcularTotalEstadias(Long clienteId, List<Checkout> checkoutList) {
        checkoutsProcessadosPorCliente.putIfAbsent(clienteId, new HashSet<>());
        Set<Long> checkoutsProcessados = checkoutsProcessadosPorCliente.get(clienteId);

        BigDecimal totalAtual = totalPorCliente.getOrDefault(clienteId, BigDecimal.ZERO);

        for (Checkout checkout : checkoutList) {
            if (!checkoutsProcessados.contains(checkout.getId())) {
                totalAtual = totalAtual.add(checkout.getValorTotal());
                checkoutsProcessados.add(checkout.getId());
            }
        }

        totalPorCliente.put(clienteId, totalAtual);
        return totalAtual;
    }
}

package com.desafio.hotel.services.guests;

import com.desafio.hotel.dto.guest.GuestDto;
import com.desafio.hotel.entity.guest.Guest;
import java.util.List;

/**
 * Interface para o serviço de hóspedes. Implementada por GuestServiceImpl.
 */
public interface GuestService {
    Guest cadastrarHospede(GuestDto dto);
    List<Guest> filtroDeBusca(String nome, String documento, String telefone);
    String deletarGuestById(Long id);
    Guest findById(Long guestId);
    List<Guest> buscarTodosHospedes();
    List<Guest> buscarHospedeDentroOuForaHotel(boolean dentroHotel);
}

package com.desafio.hotel.services.guests;

import com.desafio.hotel.dto.guest.GuestDto;
import com.desafio.hotel.entity.guest.Guest;
import com.desafio.hotel.exceptions.BadRequestException;
import com.desafio.hotel.exceptions.GuestNotFoundException;
import com.desafio.hotel.repositories.GuestRepository;
import com.desafio.hotel.specification.GuestSpecification;
import com.desafio.hotel.specification.criteria.SearchCriteria;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.jpa.domain.Specification;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * Serviço responsável pela gestão de hóspedes.
 *
 * <p>Esta classe fornece operações para cadastrar, buscar, deletar e filtrar hóspedes
 * do hotel. Implementa funcionalidades de busca com critérios múltiplos.</p>
 *
 * <p>Funcionalidades principais:</p>
 * <ul>
 *   <li>Cadastrar novos hóspedes no sistema</li>
 *   <li>Buscar hóspedes por diversos critérios (nome, documento, telefone)</li>
 *   <li>Deletar hóspedes do sistema</li>
 *   <li>Listar hóspedes que estão dentro ou fora do hotel</li>
 *   <li>Normalização de dados (remoção de caracteres especiais)</li>
 * </ul>
 *
 * @author Kaike Tinoco
 * @version 1.0
 * @since 1.0
 */
@Service
public class GuestServiceImpl implements GuestService {

    private final GuestRepository repository;

    @Autowired
    public GuestServiceImpl(GuestRepository repository) {
        this.repository = repository;
    }

    /**
     * Cadastra um novo hóspede no sistema.
     *
     * <p>Normaliza o nome removendo espaços e convertendo para minúsculas,
     * e remove caracteres especiais de documentos e telefones.</p>
     *
     * @param dto objeto contendo os dados do hóspede a cadastrar
     * @return o hóspede cadastrado
     * @throws BadRequestException se houver erro ao salvar o hóspede
     */
    @Override
    public Guest cadastrarHospede(GuestDto dto){
        try {
            Guest guest = new Guest();
            guest.setNome(dto.getNome().toLowerCase().replace(" ","_"));
            guest.setDocumento(excluirTracosePontos(dto.getDocumento()));
            guest.setTelefone(excluirTracosePontos(dto.getTelefone()));
            guest.setDentroHotel(true);
            salvarGuest(guest);
            return guest;
        } catch (BadRequestException e) {
            throw new BadRequestException("Erro ao tentar salvar o hóspede, contate o  suporte");
        }

    }

    /**
     * Busca hóspedes aplicando filtros opcionais.
     *
     * <p>Permite filtrar por nome, documento e/ou telefone. Se nenhum filtro
     * for fornecido, retorna todos os hóspedes.</p>
     *
     * @param nome nome do hóspede (opcional)
     * @param documento documento do hóspede (opcional)
     * @param telefone telefone do hóspede (opcional)
     * @return lista de hóspedes que correspondem aos critérios
     */
    @Override
    public List<Guest> filtroDeBusca(String nome, String documento, String telefone){
        if(validarParametros(nome, documento, telefone)){
            GuestSpecification nomeSpecification = null;
            GuestSpecification documentoSpecification = null;
            GuestSpecification telefoneSpecification = null;

            if (nome != null){
                nomeSpecification = getGuestSpecifcationName(nome);
            }
            if(documento!= null){
                documentoSpecification = getGuestSpecifcationDocument(documento);
            }
            if(telefone!= null){
                telefoneSpecification = getGuestSpecifcationTelefone(telefone);
            }

            Specification<Guest>guestSpecification = Specification.where(nomeSpecification)
                    .and(documentoSpecification)
                    .and(telefoneSpecification);
            return repository.findAll(guestSpecification);
        }
        return buscarTodosHospedes();

    }

    /**
     * Cria uma especificação para buscar hóspedes por nome.
     *
     * @param name nome a ser buscado (usa busca parcial)
     * @return GuestSpecification para busca por nome
     */
    private GuestSpecification getGuestSpecifcationName(String name){
        GuestSpecification guestSpecification;
        guestSpecification=GuestSpecification.builder()
                .criteria(SearchCriteria.builder()
                        .key("nome")
                        .value(name)
                        .operation("%")
                        .build())
                .build();
        return guestSpecification;
    }

    /**
     * Cria uma especificação para buscar hóspedes por documento.
     *
     * @param document documento a ser buscado (usa busca parcial)
     * @return GuestSpecification para busca por documento
     */
    private GuestSpecification getGuestSpecifcationDocument(String document){
        GuestSpecification guestSpecification;
        guestSpecification=GuestSpecification.builder()
                .criteria(SearchCriteria.builder()
                        .key("documento")
                        .value(document)
                        .operation("%")
                        .build())
                .build();
        return guestSpecification;
    }

    /**
     * Cria uma especificação para buscar hóspedes por telefone.
     *
     * @param telefone telefone a ser buscado (usa busca parcial)
     * @return GuestSpecification para busca por telefone
     */
    private GuestSpecification getGuestSpecifcationTelefone(String telefone){
        GuestSpecification guestSpecification;
        guestSpecification=GuestSpecification.builder()
                .criteria(SearchCriteria.builder()
                        .key("telefone")
                        .value(telefone)
                        .operation("%")
                        .build())
                .build();
        return guestSpecification;
    }

    /**
     * Valida se pelo menos um parâmetro de filtro foi fornecido.
     *
     * @param nome filtro por nome
     * @param documento filtro por documento
     * @param telefone filtro por telefone
     * @return true se pelo menos um parâmetro não é nulo
     */
    private boolean validarParametros(String nome, String documento, String telefone){
        return !(nome == null && documento == null && telefone == null);
    }

    /**
     * Deleta um hóspede do sistema pelo seu ID.
     *
     * @param id identificador único do hóspede a deletar
     * @return mensagem confirmando a exclusão do hóspede
     * @throws BadRequestException se o ID for nulo
     * @throws GuestNotFoundException se o hóspede não for encontrado
     */
    @Override
    public String deletarGuestById(Long id){
        if (id == null){
            throw new BadRequestException("Id vazio, por favor envie um id válido");
        }
        try {
            Guest guest = repository.findById(id)
                    .orElseThrow(() -> new GuestNotFoundException("não existe um hospede com esse Id"));
            repository.delete(guest);
            return "Hóspede deletado com sucesso!";
        } catch (BadRequestException e){
            throw new BadRequestException("erro ao deletar hóspede, contate o suporte");
        }

    }

    /**
     * Salva um hóspede no repositório.
     *
     * @param guest hóspede a ser salvo
     */
    private void salvarGuest(Guest guest){
        repository.save(guest);
    }

    /**
     * Busca um hóspede por ID.
     *
     * @param guestId identificador único do hóspede
     * @return o hóspede encontrado
     * @throws BadRequestException se o ID for nulo
     * @throws GuestNotFoundException se o hóspede não for encontrado
     */
    @Override
    public Guest findById(Long guestId) {
        if(guestId == null){
            throw new BadRequestException("Id vazio, por favor envie um id válido");
        }
        try {
            return repository.findById(guestId)
                    .orElseThrow(() -> new GuestNotFoundException("Hospede não encontrado, Id inválido"));
        }catch (BadRequestException e){
            throw new BadRequestException("erro ao buscar o hóspede, contate o suporte");
        }
    }

    /**
     * Remove caracteres especiais de uma string.
     *
     * <p>Remove espaços em branco, pontos, barras, hífens e parênteses.</p>
     *
     * @param s string a ser processada
     * @return string sem caracteres especiais
     */
    private String excluirTracosePontos(String s){
        s = s.replace( " " , ""); //tira espaço em branco
        s = s.replace( "." , ""); //tira ponto
        s = s.replace( "/" , ""); //tira barra
        s = s.replace( "-" , "");//tira hífen
        s = s.replace("(", "");
        s = s.replace(")","");
        return s;
    }

    /**
     * Busca todos os hóspedes cadastrados no sistema.
     *
     * @return lista com todos os hóspedes
     */
    @Override
    public List<Guest> buscarTodosHospedes() {
        return repository.findAll();
    }

    /**
     * Busca hóspedes de acordo com sua posição no hotel.
     *
     * @param dentroHotel true para buscar hóspedes dentro do hotel, false para fora
     * @return lista de hóspedes de acordo com o critério
     * @throws BadRequestException se nenhum hóspede for encontrado
     */
    @Override
    public List<Guest> buscarHospedeDentroOuForaHotel(boolean dentroHotel){
        String mensagemErro = dentroHotel?"Não há pessoas dentro do hotel!":"Não há pessoas fora do hotel!";
        return repository.findByDentroHotel(dentroHotel)
                    .orElseThrow(() -> new BadRequestException(mensagemErro));

    }


}
